    74→func (p *Progress) lastTopic() (status string, sectionNumber int, topicNumber int) {
    75→	var maxRecord ProgressRecord = ProgressRecord{ "", "", 0, 0, "not started", "", nil };
    76→
    77→	for _, record := range p.records {
    78→		if record.sectionNumber > maxRecord.sectionNumber || (record.sectionNumber == maxRecord.sectionNumber && record.topicNumber > maxRecord.topicNumber) {
    79→			maxRecord = record
    80→		}
    81→	}
    82→
    83→	return maxRecord.status, maxRecord.sectionNumber, maxRecord.topicNumber
    84→}
    85→
    86→func (p *Progress) start(section Section, topic Topic) {
    87→	for _, record := range p.records {
    88→		// 開始済み、完了済みの場合は何もしない
    89→		if record.courseSectionTopicId == topic.topicId && record.courseSectionId == section.sectionId {
    90→			return;
    91→		}
    92→	}
    93→
    94→
    95→	p.records = append(p.records, ProgressRecord{
    96→		courseSectionId: section.sectionId,
    97→		courseSectionTopicId: topic.topicId,
    98→		sectionNumber: section.number,
    99→		topicNumber: topic.number,
   100→		status: "started",
   101→		startedAt: time.Now().Format(time.RFC3339),
   102→		completedAt: nil,
   103→	})
   104→}
