   108→var ErrEnrollmentNumberIsNotFound = errors.New("enrollment number is not found");
   109→
   110→func (course *Course)enroll(enrollNumber EnrollNumber, progress *Progress) (error){
   111→	sectionNumber := 0
   112→	topicNumber := 0
   113→
   114→	if enrollNumber.SectionNumber != nil {
   115→		sectionNumber = *enrollNumber.SectionNumber;
   116→
   117→		if enrollNumber.TopicNumber == nil {
   118→			topicNumber = 0;
   119→		} else {
   120→			topicNumber = *enrollNumber.TopicNumber;
   121→		}
   122→
   123→	} else if enrollNumber.SectionNumber == nil && enrollNumber.TopicNumber == nil {
   124→		status, lastSectionNumber, lastTopicNumber := progress.lastTopic();
   125→		if status== "completed" {
   126→			nextPosition, err := course.nextTopic(TopicPosition{sectionNumber: lastSectionNumber, topicNumber: lastTopicNumber})
   127→
   128→			if err != nil {
   129→				return  ErrEnrollmentNumberIsNotFound
   130→			}
   131→			sectionNumber, topicNumber = nextPosition.sectionNumber, nextPosition.topicNumber
   132→		} else if status == "started" {
   133→			sectionNumber = lastSectionNumber
   134→			topicNumber =  lastTopicNumber
   135→		} else {
   136→			sectionNumber = 1
   137→			topicNumber = 1
   138→		}
   139→	}
   140→
   141→	section, topic, err := course.getTopic(sectionNumber, topicNumber)
   142→	if err != nil {
   143→		return  ErrEnrollmentNumberIsNotFound;
   144→	}
   145→
   146→	progress.start(section, topic)
   147→
   148→	return nil;
   149→}
