   151→type TopicPosition struct {
   152→	sectionNumber int
   153→	topicNumber int
   154→}
   155→
   156→var ErrTopicPositionOutOfRange = errors.New("topic position is out of range")
   157→
   158→func (course *Course) getTopic(sectionNumber int, topicNumber int) (Section, Topic, error) {
   159→	if sectionNumber < 1 || sectionNumber > len(course.sections) {
   160→		return Section{}, Topic{}, ErrTopicPositionOutOfRange
   161→	}
   162→	section := course.sections[sectionNumber-1]
   163→	if topicNumber < 1 || topicNumber > len(section.topics) {
   164→		return Section{}, Topic{}, ErrTopicPositionOutOfRange
   165→	}
   166→	return section, section.topics[topicNumber-1], nil
   167→}
   168→
   169→func (course *Course) nextTopic(currentTopicPosition TopicPosition) (topicPosition TopicPosition, err error) {
   170→	if currentTopicPosition.sectionNumber >= len(course.sections) || currentTopicPosition.sectionNumber < 0 {
   171→		return TopicPosition{}, ErrTopicPositionOutOfRange
   172→	}
   173→
   174→	if currentTopicPosition.topicNumber >= len(course.sections[currentTopicPosition.sectionNumber].topics) || currentTopicPosition.topicNumber < 0 {
   175→		return TopicPosition{}, ErrTopicPositionOutOfRange
   176→	}
   177→
   178→	if currentTopicPosition.topicNumber == len(course.sections[currentTopicPosition.sectionNumber].topics) {
   179→		if currentTopicPosition.sectionNumber == len(course.sections) {
   180→			return TopicPosition{sectionNumber: 1, topicNumber: 1}, nil
   181→		}
   182→
   183→		return TopicPosition{sectionNumber: currentTopicPosition.sectionNumber + 1, topicNumber: 1}, nil
   184→	}
   185→
   186→	return TopicPosition{sectionNumber: currentTopicPosition.sectionNumber, topicNumber: currentTopicPosition.topicNumber + 1}, nil
   187→
   188→}
